namespace AutoVistaTestBench.Core.Models
{
    /// <summary>
    /// Represents an anomaly or fault event detected during a test session.
    /// Anomaly reports are generated by threshold violations and can optionally
    /// be enriched by AI analysis for root cause suggestions.
    /// </summary>
    public class AnomalyReport
    {
        /// <summary>Unique identifier for this anomaly.</summary>
        public Guid AnomalyId { get; set; } = Guid.NewGuid();

        /// <summary>UTC timestamp when the anomaly was first detected.</summary>
        public DateTime DetectedAt { get; set; } = DateTime.UtcNow;

        /// <summary>Channel ID where the anomaly occurred.</summary>
        public string ChannelId { get; set; } = string.Empty;

        /// <summary>Channel name for human-readable reporting.</summary>
        public string ChannelName { get; set; } = string.Empty;

        /// <summary>The measured value that triggered the anomaly.</summary>
        public double TriggerValue { get; set; }

        /// <summary>The threshold that was exceeded.</summary>
        public double ThresholdValue { get; set; }

        /// <summary>Short description of the anomaly type.</summary>
        public string Description { get; set; } = string.Empty;

        /// <summary>
        /// Optional: AI-generated analysis and root cause suggestion.
        /// Populated by the AiAnalysisService after submission to LLM API.
        /// </summary>
        public string? AiAnalysis { get; set; }

        /// <summary>True if AI analysis has been requested and received.</summary>
        public bool IsAiAnalyzed => AiAnalysis != null;

        /// <summary>Severity label for this anomaly.</summary>
        public string SeverityLabel => TriggerValue >= ThresholdValue * 1.2 ? "CRITICAL" : "WARNING";

        public override string ToString() =>
            $"[ANOMALY {AnomalyId:N}] {DetectedAt:HH:mm:ss} | {ChannelName} | " +
            $"Value:{TriggerValue:F3} | Threshold:{ThresholdValue:F3} | {Description}";
    }
}